import { useAuth } from '../context/AuthContext';
import { HiOutlineShoppingBag, HiOutlineViewGrid, HiOutlineClipboardList, HiOutlineUser, HiOutlineCog, HiOutlineUsers, HiOutlineTag, HiOutlineShoppingCart, HiOutlineCollection } from 'react-icons/hi';
import './Navbar.css';

export default function Navbar({ onToggleSidebar, cartCount = 0 }) {
  const { user, isAuthenticated, logout, isAdmin } = useAuth();
  const location = useLocation();

  return (
    <nav className="navbar glass-strong">
      <div className="navbar-left">
        <button className="navbar-toggle btn-icon btn-ghost" onClick={onToggleSidebar} id="sidebar-toggle">
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
            <path d="M3 5h14M3 10h14M3 15h14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
          </svg>
        </button>
        <Link to="/" className="navbar-brand" id="brand-link">
          <span className="navbar-logo gradient-text">M</span>
          <span className="navbar-title">MINI-SHOP-DB</span>
        </Link>
      </div>

      <div className="navbar-right">
        {isAuthenticated ? (
          <>
            <Link to="/cart" className="navbar-cart-btn btn-ghost btn-icon" id="cart-nav-btn">
              <HiOutlineShoppingBag size={22} />
              {cartCount > 0 && <span className="cart-badge">{cartCount}</span>}
            </Link>

            <div className="navbar-user" id="user-menu">
              <div className="navbar-user-info hide-mobile">
                <span className="navbar-user-name">{user?.name}</span>
                <span className="navbar-user-balance">₽{Number(user?.balance || 0).toLocaleString('ru-RU', { minimumFractionDigits: 2 })}</span>
              </div>
              <div className="navbar-avatar">
                {user?.picture ? (
                  <img src={user.picture} alt={user.name} referrerPolicy="no-referrer" />
                ) : (
                  <span>{user?.name?.[0] || '?'}</span>
                )}
              </div>
            </div>
          </>
        ) : (
          <Link to="/login" className="btn btn-primary" id="login-nav-btn">Sign In</Link>
        )}
      </div>
    </nav>
  );
}

import { NavLink, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { HiOutlineViewGrid, HiOutlineShoppingBag, HiOutlineClipboardList, HiOutlineUser, HiOutlineCreditCard, HiOutlineCog, HiOutlineUsers, HiOutlineTag, HiOutlineShoppingCart, HiOutlineCollection, HiOutlineLogout, HiOutlineLogin } from 'react-icons/hi';
import './Sidebar.css';

export default function Sidebar({ isOpen, onClose }) {
  const { isAuthenticated, isAdmin, logout } = useAuth();

  const publicLinks = [
    { to: '/', icon: <HiOutlineViewGrid size={20} />, label: 'Каталог' },
  ];

  const userLinks = [
    { to: '/cart', icon: <HiOutlineShoppingBag size={20} />, label: 'Корзина' },
    { to: '/orders', icon: <HiOutlineClipboardList size={20} />, label: 'Заказы' },
    { to: '/profile', icon: <HiOutlineUser size={20} />, label: 'Профиль' },
  ];

  const adminLinks = [
    { to: '/admin', icon: <HiOutlineCog size={20} />, label: 'Dashboard' },
    { to: '/admin/products', icon: <HiOutlineTag size={20} />, label: 'Товары' },
    { to: '/admin/categories', icon: <HiOutlineCollection size={20} />, label: 'Категории' },
    { to: '/admin/orders', icon: <HiOutlineClipboardList size={20} />, label: 'Заказы' },
    { to: '/admin/users', icon: <HiOutlineUsers size={20} />, label: 'Пользователи' },
    { to: '/admin/carts', icon: <HiOutlineShoppingCart size={20} />, label: 'Корзины' },
  ];

  return (
    <>
      {isOpen && <div className="sidebar-overlay" onClick={onClose} />}
      <aside className={`sidebar glass-strong ${isOpen ? 'sidebar-open' : ''}`} id="sidebar">
        <div className="sidebar-content">
          {/* Public section — always visible */}
          <div className="sidebar-section">
            <span className="sidebar-section-title">Магазин</span>
            <nav className="sidebar-nav">
              {publicLinks.map(link => (
                <NavLink
                  key={link.to}
                  to={link.to}
                  end
                  className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}
                  onClick={onClose}
                >
                  {link.icon}
                  <span>{link.label}</span>
                </NavLink>
              ))}

              {isAuthenticated && userLinks.map(link => (
                <NavLink
                  key={link.to}
                  to={link.to}
                  className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}
                  onClick={onClose}
                >
                  {link.icon}
                  <span>{link.label}</span>
                </NavLink>
              ))}
            </nav>
          </div>

          {isAuthenticated && isAdmin && (
            <div className="sidebar-section">
              <span className="sidebar-section-title">Администрирование</span>
              <nav className="sidebar-nav">
                {adminLinks.map(link => (
                  <NavLink
                    key={link.to}
                    to={link.to}
                    end={link.to === '/admin'}
                    className={({ isActive }) => `sidebar-link ${isActive ? 'active' : ''}`}
                    onClick={onClose}
                  >
                    {link.icon}
                    <span>{link.label}</span>
                  </NavLink>
                ))}
              </nav>
            </div>
          )}

          <div className="sidebar-footer">
            {isAuthenticated ? (
              <button className="sidebar-link sidebar-logout" onClick={() => { logout(); onClose(); }} id="logout-btn">
                <HiOutlineLogout size={20} />
                <span>Выйти</span>
              </button>
            ) : (
              <Link to="/login" className="sidebar-link sidebar-login" onClick={onClose} id="sidebar-login-btn">
                <HiOutlineLogin size={20} />
                <span>Войти</span>
              </Link>
            )}
          </div>
        </div>
      </aside>
    </>
  );
}

