            {orders.map(order => (
              <OrderCard key={order.id} order={order} onCancel={handleCancel} />
            ))}
          </div>
          <Pagination page={page} onPageChange={setPage} hasMore={orders.length === 30} />
        </>
      )}
    </div>
  );
}

